// FIX: data zit onder .body omdat n8n de webhook payload zo structureert
const d = $input.first().json.body;

const formatEuro = (v) =>
  v != null
    ? new Intl.NumberFormat('nl-NL', { style: 'currency', currency: 'EUR' }).format(v)
    : null;

const escapeHtml = (value) =>
  String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');

const dateNL = new Intl.DateTimeFormat('nl-NL', { dateStyle: 'long' }).format(new Date());
const proposalRef = d.proposalId ? String(d.proposalId).slice(-8).toUpperCase() : 'ONBEKEND';
const summaryHtml = escapeHtml(d.summary ?? '').replace(/\n/g, '<br/>');
const notesHtml = escapeHtml(d.notes ?? '').replace(/\n/g, '<br/>');
const addressHtml = escapeHtml(d.recipientAddress ?? '').replace(/\n/g, '<br/>');

const scopeHtml = d.scope
  ? String(d.scope).split('\n').map(l => l.trim()).filter(Boolean).map(l => `<li>${escapeHtml(l)}</li>`).join('')
  : '';

const html = `<!DOCTYPE html>
<html lang="nl">
<head>
  <meta charset="UTF-8" />
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: 'Helvetica Neue', Arial, sans-serif; font-size: 13px; color: #1a1a1a; padding: 48px; }
    .header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 48px; }
    .logo { font-size: 22px; font-weight: 700; color: #111; }
    .meta { text-align: right; font-size: 12px; color: #555; line-height: 1.8; }
    h1 { font-size: 26px; font-weight: 700; margin-bottom: 4px; }
    .subtitle { font-size: 13px; color: #666; margin-bottom: 36px; }
    .two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 32px; margin-bottom: 36px; }
    .block-label { font-size: 10px; font-weight: 600; text-transform: uppercase; letter-spacing: .08em; color: #999; margin-bottom: 6px; }
    .block-value { font-size: 13px; line-height: 1.7; }
    section { margin-bottom: 28px; }
    section h2 { font-size: 13px; font-weight: 600; text-transform: uppercase; letter-spacing: .06em; color: #777; border-bottom: 1px solid #e5e7eb; padding-bottom: 6px; margin-bottom: 12px; }
    section p, section ul { font-size: 13px; line-height: 1.8; color: #333; }
    section ul { padding-left: 18px; }
    .price-box { background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 8px; padding: 20px 24px; display: flex; justify-content: space-between; align-items: center; margin-bottom: 28px; }
    .price-label { font-size: 13px; font-weight: 600; color: #374151; }
    .price-amount { font-size: 22px; font-weight: 700; color: #111; }
    .footer { margin-top: 48px; font-size: 11px; color: #aaa; text-align: center; border-top: 1px solid #f0f0f0; padding-top: 16px; }
  </style>
</head>
<body>
  <div class="header">
    <div class="logo">Agency OS</div>
    <div class="meta"><strong>OFFERTE</strong><br/>Datum: ${dateNL}<br/>Ref: ${proposalRef}</div>
  </div>
  <h1>${escapeHtml(d.title ?? 'Offerte')}</h1>
  <p class="subtitle">Opgesteld voor ${escapeHtml(d.recipientCompany ?? d.recipientName ?? '')}</p>
  <div class="two-col">
    <div>
      <div class="block-label">Aan</div>
      <div class="block-value">${escapeHtml(d.recipientName ?? '')}<br/>${escapeHtml(d.recipientCompany ?? '')}<br/>${addressHtml}</div>
    </div>
    <div>
      <div class="block-label">Contactgegevens</div>
      <div class="block-value">${escapeHtml(d.recipientEmail ?? '')}</div>
    </div>
  </div>
  <section><h2>Samenvatting</h2><p>${summaryHtml}</p></section>
  ${scopeHtml ? `<section><h2>Scope van het werk</h2><ul>${scopeHtml}</ul></section>` : ''}
  ${d.deliveryTime ? `<section><h2>Doorlooptijd</h2><p>${escapeHtml(d.deliveryTime)}</p></section>` : ''}
  ${d.amount != null ? `<div class="price-box"><span class="price-label">${escapeHtml(d.priceLabel ?? 'Projectprijs')}</span><span class="price-amount">${formatEuro(d.amount)}</span></div>` : ''}
  ${d.notes ? `<section><h2>Opmerkingen</h2><p>${notesHtml}</p></section>` : ''}
  <div class="footer">Deze offerte is vrijblijvend en geldig voor 30 dagen.</div>
</body>
</html>`;

return [{ json: { ...d, html } }];

const html = $input.first().json.html;
const buffer = Buffer.from(html, 'utf8');
const binaryData = {
  data: buffer.toString('base64'),
  mimeType: 'application/octet-stream',
  fileName: 'offerte.html'
};
const item = $input.first();
item.binary = { data: binaryData };
return [item];
